private function generateAlterTableSql(string $createTableSql, array $moveColumns): ?string
{
    $parser = new Parser($createTableSql);
    /** @var CreateStatement $statement */
    $statement = $parser->statements[0];
    /** @var CreateDefinition[] $fields For CREATE TABLE statement the type is CreateDefinition[] */
    $fields = $statement->fields;
    $columns = [];
    foreach ($fields as $field) {
        if ($field->name === null || $field->isConstraint === true || $field->key !== null) {
            continue;
        }

        $columns[$field->name] = $field;
    }

    $columnNames = array_keys($columns);
    // Ensure the columns from client match the columns from the table
    if (
        count($columnNames) !== count($moveColumns) ||
        array_diff($columnNames, $moveColumns) !== []
    ) {
        return null;
    }

    $changes = [];

    // move columns from first to last
    /** @psalm-var list<string> $moveColumns */
    foreach ($moveColumns as $i => $columnName) {
        // is this column already correctly placed?
        if ($columnNames[$i] == $columnName) {
            continue;
        }

        $changes[] =
            'CHANGE ' . Util::backquote($columnName) . ' ' . CreateDefinition::build($columns[$columnName]) .
            ($i === 0 ? ' FIRST' : ' AFTER ' . Util::backquote($columnNames[$i - 1]));

        // Move column to its new position
        /** @var int $j */
        $j = array_search($columnName, $columnNames, true);
        array_splice($columnNames, $j, 1);
        array_splice($columnNames, $i, 0, $columnName);
    }

    if ($changes === []) {
        return null;
    }

    assert($statement->name !== null, 'Alter table statement has no name');

    return 'ALTER TABLE ' . Util::backquote($statement->name->table) . "\n  " . implode(",\n  ", $changes);
}

public static function downloadHeader(
    string $filename,
    string $mimetype,
    int $length = 0,
    bool $noCache = true
): void {
    $headers = self::getDownloadHeaders($filename, $mimetype, $length, $noCache);

    // The default output in PMA uses gzip,
    // so if we want to output uncompressed file, we should reset the encoding.
    // See PHP bug https://github.com/php/php-src/issues/8218
    header_remove('Content-Encoding');

    foreach ($headers as $name => $value) {
        header(sprintf('%s: %s', $name, $value));
    }
}

public static function getDownloadHeaders(
    string $filename,
    string $mimetype,
    int $length = 0,
    bool $noCache = true
): array {
    $headers = [];

    if ($noCache) {
        $headers = self::getNoCacheHeaders();
    }

    /* Replace all possibly dangerous chars in filename */
    $filename = Sanitize::sanitizeFilename($filename);
    if ($filename !== '') {
        $headers['Content-Description'] = 'File Transfer';
        $headers['Content-Disposition'] = 'attachment; filename="' . $filename . '"';
    }

    $headers['Content-Type'] = $mimetype;

    $headers['Content-Transfer-Encoding'] = 'binary';

    if ($length > 0) {
        $headers['Content-Length'] = (string) $length;
    }

    return $headers;
}

public static function sendHeaderLocation(string $uri, bool $use_refresh = false): void
{
    if ($GLOBALS['config']->get('PMA_IS_IIS') && mb_strlen($uri) > 600) {
        ResponseRenderer::getInstance()->disable();

        $template = new Template();
        echo $template->render('header_location', ['uri' => $uri]);

        return;
    }

    /*
     * Avoid relative path redirect problems in case user entered URL
     * like /phpmyadmin/index.php/ which some web servers happily accept.
     */
    if ($uri[0] === '.') {
        $uri = $GLOBALS['config']->getRootPath() . substr($uri, 2);
    }

    $response = ResponseRenderer::getInstance();

    session_write_close();
    if ($response->headersSent()) {
        trigger_error(
            'Core::sendHeaderLocation called when headers are already sent!',
            PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
        );
    }

    // bug #1523784: IE6 does not like 'Refresh: 0', it
    // results in a blank page
    // but we need it when coming from the cookie login panel)
    if ($GLOBALS['config']->get('PMA_IS_IIS') && $use_refresh) {
        $response->header('Refresh: 0; ' . $uri);

        return;
    }

    $response->header('Location: ' . $uri);
}

