public function getTableDef(
    $db,
    $table,
    $do_relation,
    $do_comments,
    $do_mime,
    $view = false,
    array $aliases = []
): void {
    global $dbi;

    $relationParameters = $this->relation->getRelationParameters();

    unset(
        $this->tablewidths,
        $this->colTitles,
        $this->titleWidth,
        $this->colFits,
        $this->displayColumn,
        $this->colAlign
    );

    /**
     * Gets fields properties
     */
    $dbi->selectDb($db);

    /**
     * All these three checks do_relation, do_comment and do_mime is
     * not required. As presently all are set true by default.
     * But when, methods to take user input will be developed,
     * it will be of use
     */
    // Check if we can use Relations
    if ($do_relation) {
        // Find which tables are related with the current one and write it in
        // an array
        $res_rel = $this->relation->getForeigners($db, $table);
        $have_rel = ! empty($res_rel);
    } else {
        $have_rel = false;
    }

    //column count and table heading

    $this->colTitles[0] = __('Column');
    $this->tablewidths[0] = 90;
    $this->colTitles[1] = __('Type');
    $this->tablewidths[1] = 80;
    $this->colTitles[2] = __('Null');
    $this->tablewidths[2] = 40;
    $this->colTitles[3] = __('Default');
    $this->tablewidths[3] = 120;

    for ($columns_cnt = 0; $columns_cnt < 4; $columns_cnt++) {
        $this->colAlign[$columns_cnt] = 'L';
        $this->displayColumn[$columns_cnt] = true;
    }

    if ($do_relation && $have_rel) {
        $this->colTitles[$columns_cnt] = __('Links to');
        $this->displayColumn[$columns_cnt] = true;
        $this->colAlign[$columns_cnt] = 'L';
        $this->tablewidths[$columns_cnt] = 120;
    }

    if ($do_comments) {
        $columns_cnt++;
        $this->colTitles[$columns_cnt] = __('Comments');
        $this->displayColumn[$columns_cnt] = true;
        $this->colAlign[$columns_cnt] = 'L';
        $this->tablewidths[$columns_cnt] = 120;
    }

    if ($do_mime && $relationParameters->browserTransformationFeature !== null) {
        $columns_cnt++;
        $this->colTitles[$columns_cnt] = __('Media type');
        $this->displayColumn[$columns_cnt] = true;
        $this->colAlign[$columns_cnt] = 'L';
        $this->tablewidths[$columns_cnt] = 120;
    }

    // Starting to fill table with required info

    $this->setY($this->tMargin);
    $this->AddPage();
    $this->setFont(PdfLib::PMA_PDF_FONT, '', 9);

    // Now let's start to write the table structure

    if ($do_comments) {
        $comments = $this->relation->getComments($db, $table);
    }

    if ($do_mime && $relationParameters->browserTransformationFeature !== null) {
        $mime_map = $this->transformations->getMime($db, $table, true);
    }

    $columns = $dbi->getColumns($db, $table);

    // some things to set and 'remember'
    $l = $this->lMargin;
    $startheight = $h = $this->dataY;
    $startpage = $currpage = $this->page;
    // calculate the whole width
    $fullwidth = 0;
    foreach ($this->tablewidths as $width) {
        $fullwidth += $width;
    }

    $row = 0;
    $tmpheight = [];
    $maxpage = $this->page;
    $data = [];

    // fun begin
    foreach ($columns as $column) {
        $extracted_columnspec = Util::extractColumnSpec($column['Type']);

        $type = $extracted_columnspec['print_type'];
        if (empty($type)) {
            $type = ' ';
        }

        if (! isset($column['Default'])) {
            if ($column['Null'] !== 'NO') {
                $column['Default'] = 'NULL';
            }
        }

        $data[] = $column['Field'];
        $data[] = $type;
        $data[] = $column['Null'] == '' || $column['Null'] === 'NO'
            ? 'No'
            : 'Yes';
        $data[] = $column['Default'] ?? '';

        $field_name = $column['Field'];

        if ($do_relation && $have_rel) {
            $data[] = isset($res_rel[$field_name])
                ? $res_rel[$field_name]['foreign_table']
                . ' (' . $res_rel[$field_name]['foreign_field']
                . ')'
                : '';
        }

        if ($do_comments) {
            $data[] = $comments[$field_name] ?? '';
        }

        if ($do_mime) {
            $data[] = isset($mime_map[$field_name])
                ? $mime_map[$field_name]['mimetype']
                : '';
        }

        $this->page = $currpage;
        // write the horizontal borders
        $this->Line($l, $h, $fullwidth + $l, $h);
        // write the content and remember the height of the highest col
        foreach ($data as $col => $txt) {
            $this->page = $currpage;
            $this->setXY($l, $h);
            if (isset($this->tablewidths[$col]) && $this->tablewidths[$col] > 0) {
                $this->MultiCell(
                    $this->tablewidths[$col],
                    // phpcs:ignore Squiz.NamingConventions.ValidVariableName.MemberNotCamelCaps
                    $this->FontSizePt,
                    $txt ?? 'NULL',
                    0,
                    $this->colAlign[$col]
                );
                $l += $this->tablewidths[$col];
            }

            if (! isset($tmpheight[$row . '-' . $this->page])) {
                $tmpheight[$row . '-' . $this->page] = 0;
            }

            if ($tmpheight[$row . '-' . $this->page] < $this->GetY()) {
                $tmpheight[$row . '-' . $this->page] = $this->GetY();
            }

            if ($this->page <= $maxpage) {
                continue;
            }

            $maxpage = $this->page;
        }

        // get the height we were in the last used page
        $h = $tmpheight[$row . '-' . $maxpage];
        // set the "pointer" to the left margin
        $l = $this->lMargin;
        // set the $currpage to the last page
        $currpage = $maxpage;
        unset($data);
        $row++;
    }

    // draw the borders
    // we start adding a horizontal line on the last page
    $this->page = $maxpage;
    $this->Line($l, $h, $fullwidth + $l, $h);
    // now we start at the top of the document and walk down
    for ($i = $startpage; $i <= $maxpage; $i++) {
        $this->page = $i;
        $l = $this->lMargin;
        $t = $i == $startpage ? $startheight : $this->tMargin;
        $lh = $i == $maxpage ? $h : $this->h - $this->bMargin;
        $this->Line($l, $t, $l, $lh);
        foreach ($this->tablewidths as $width) {
            $l += $width;
            $this->Line($l, $t, $l, $lh);
        }
    }

    // set it to the last page, if not it'll cause some problems
    $this->page = $maxpage;
}

private function getTableNameFromImport(string $databaseName): string
{
    global $import_file_name, $dbi;

    $importFileName = basename($import_file_name, '.csv');
    $importFileName = mb_strtolower($importFileName);
    $importFileName = (string) preg_replace('/[^a-zA-Z0-9_]/', '_', $importFileName);

    // get new table name, if user didn't provide one, set the default name
    if (isset($_REQUEST['csv_new_tbl_name']) && strlen($_REQUEST['csv_new_tbl_name']) > 0) {
        return $_REQUEST['csv_new_tbl_name'];
    }

    if (mb_strlen($databaseName)) {
        $result = $dbi->fetchResult('SHOW TABLES');

        // logic to get table name from filename
        // if no table then use filename as table name
        if (count($result) === 0) {
            return $importFileName;
        }

        // check to see if {filename} as table exist
        $nameArray = preg_grep('/^' . $importFileName . '$/isU', $result);
        // if no use filename as table name
        if ($nameArray === false || count($nameArray) === 0) {
            return $importFileName;
        }

        // check if {filename}_ as table exist
        $nameArray = preg_grep('/^' . $importFileName . '_$/isU', $result);
        if ($nameArray === false) {
            return $importFileName;
        }

        // Filter for table names starting with the {filename}_ prefix
        $nameArray = preg_grep('/^' . $importFileName . '_/isU', $result);

        return $importFileName . '_' . (count($nameArray) + 1);
    }

    return $importFileName;
}

public static function getInformationSchemaDataForCreateRequest(
    string $user,
    string $host,
    string $collation
): string {
    // second part of query is for MariaDB that not show roles inside INFORMATION_SCHEMA db
    return 'SELECT 1 FROM `INFORMATION_SCHEMA`.`USER_PRIVILEGES` '
        . "WHERE `PRIVILEGE_TYPE` = 'CREATE USER' AND "
        . "'''" . $user . "''@''" . $host . "''' LIKE `GRANTEE`"
        . ' UNION '
        . 'SELECT 1 FROM mysql.user '
        . "WHERE `create_user_priv` = 'Y' COLLATE " . $collation . ' AND '
        . "'" . $user . "' LIKE `User` AND '' LIKE `Host`"
        . ' LIMIT 1';
}

public function getList(array $params): array
{
    $urlParams = [];

    $showFullSql = ! empty($params['full']);
    if ($showFullSql) {
        $urlParams['full'] = '';
    } else {
        $urlParams['full'] = 1;
    }

    $sqlQuery = $showFullSql
        ? 'SHOW FULL PROCESSLIST'
        : 'SHOW PROCESSLIST';
    $useIS = ! empty($params['showExecuting']) ||
        (! empty($params['order_by_field']) && ! empty($params['sort_order']));
    if ($useIS) {
        $urlParams['order_by_field'] = $params['order_by_field'];
        $urlParams['sort_order'] = $params['sort_order'];
        $urlParams['showExecuting'] = $params['showExecuting'];
        $sqlQuery = 'SELECT * FROM `INFORMATION_SCHEMA`.`PROCESSLIST` ';
    }

    if (! empty($params['showExecuting'])) {
        $sqlQuery .= ' WHERE state != "" ';
    }

    if (! empty($params['order_by_field']) && ! empty($params['sort_order'])) {
        $sqlQuery .= ' ORDER BY '
            . Util::backquote($params['order_by_field'])
            . ' ' . $params['sort_order'];
    }

    $result = $this->dbi->query($sqlQuery);
    $rows = [];
    while ($process = $result->fetchAssoc()) {
        // Array keys need to modify due to the way it has used
        // to display column values
        foreach (array_keys($process) as $key) {
            $newKey = ucfirst(mb_strtolower($key));
            if ($newKey === $key) {
                continue;
            }

            $process[$newKey] = $process[$key];
            unset($process[$key]);
        }

        $progress = ! empty($process['Progress']) ? $process['Progress'] : '---';
        if ($useIS && ! empty($process['Progress'])) {
            $stage = array_key_exists('Stage', $process) ? (int) $process['Stage'] : null;
            $maxStage = array_key_exists('Max_stage', $process) ? (int) $process['Max_stage'] : null;
            if ($stage !== null && $maxStage !== null && $maxStage > 1) {
                $progress = number_format(($stage - 1) / $maxStage * 100 + ((float) $progress) / $maxStage, 3);
            }
        }

        $rows[] = [
            'id' => $process['Id'],
            'user' => $process['User'],
            'host' => $process['Host'],
            'db' => ! isset($process['Db']) || strlen($process['Db']) === 0 ? '' : $process['Db'],
            'command' => $process['Command'],
            'time' => $process['Time'],
            'state' => ! empty($process['State']) ? $process['State'] : '---',
            'progress' => $progress,
            'info' => ! empty($process['Info']) ? Generator::formatSql($process['Info'], ! $showFullSql) : '---',
        ];
    }

    return [
        'columns' => $this->getSortableColumnsForProcessList($showFullSql, $params),
        'rows' => $rows,
        'refresh_params' => $urlParams,
        'is_mariadb' => $this->dbi->isMariaDB(),
    ];
}

