    if (! $this->checkTheme($theme)) {
        trigger_error(
            sprintf(
                __('Theme %s not found!'),
                htmlspecialchars((string) $theme)
            ),
            PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
        );

        return false;
    }

