public function testExportStructure(): void
{
    $GLOBALS['sql_compatibility'] = 'MSSQL';
    $GLOBALS['sql_backquotes'] = true;
    $GLOBALS['sql_include_comments'] = true;
    $GLOBALS['crlf'] = "\n";

    // case 1
